SELECT ?game (ABS(?runsD - ?runsP) AS ?difference) WHERE {
  ?series (wdt:P1547|wdt:P566) wd:Q334634;
          (wdt:P1547|wdt:P566) wd:Q650840.
  ?game wdt:P1010 ?series.
  ?game wdt:P2550 wd:Q334634 ?runsD.
  ?game wdt:P2550 wd:Q650840 ?runsP.
} ORDER BY DESC(?difference) LIMIT 1

